   285→          imageIds: []
   286→        });
   287→      }
   288→    });
   289→  }
   290→
   291→  return {
   292→    id: generateUUID(),
   293→    title: 'Imported Portfolio',
   294→    createdAt: new Date().toISOString(),
   295→    prompts,
   296→    images: []
   297→  };
   298→}
   299→
   300→/**
   301→ * Creates a raw text portfolio as last-resort fallback
   302→ * @param {string} content
   303→ * @returns {Portfolio}
   304→ */
   305→function createRawTextPortfolio(content) {
   306→  // Split by double newlines to create rough blocks
   307→  const blocks = content.split(/\n\n+/).filter(b => b.trim().length > 0);
